package cluster

import (
	"encoding/hex"
	"testing"

	"github.com/stretchr/testify/require"

	"github.com/gritive/GrainFS/internal/storage"
)

// byteIdentityPutCmdFixtures returns PutObjectMetaCmd fixtures whose marshaled
// bytes are frozen as golden constants captured from clean HEAD (before the
// coalesced/parts/tags vector-build dedup). The fixtures cover the edges that
// would surface a vector-build drift: nil vs empty coalesced/parts/tags,
// zero-valued EC fields, coalesced refs with and without NodeIDs, and
// multi-element vectors.
func byteIdentityPutCmdFixtures() map[string]PutObjectMetaCmd {
	return map[string]PutObjectMetaCmd{
		"empty_vectors": {
			Bucket: "bk", Key: "k", Size: 5, ETag: "e", ModTime: 1700000000,
			VersionID: "v0", PlacementGroupID: "g0",
		},
		"explicit_empty_slices": {
			Bucket: "bk", Key: "k", Size: 5, ETag: "e", ModTime: 1700000000,
			VersionID: "v0", PlacementGroupID: "g0",
			Coalesced: []CoalescedShardRef{}, Parts: []storage.MultipartPartEntry{},
			Tags: []storage.Tag{},
		},
		"multi_tags": {
			Bucket: "bk", Key: "obj", Size: 42, ETag: "etag", ModTime: 1700000001,
			VersionID: "v1", PlacementGroupID: "g1",
			Tags: []storage.Tag{{Key: "env", Value: "prod"}, {Key: "owner", Value: "alice"}},
		},
		"coalesced_zero_ec_no_nodes": {
			Bucket: "bk", Key: "obj2", Size: 99, ETag: "etag2", ModTime: 1700000002,
			VersionID: "v2", PlacementGroupID: "g2",
			Coalesced: []CoalescedShardRef{
				{CoalescedID: "c0", Size: 10, ETag: "ce0", ShardKey: "sk0", Version: 1},
				{CoalescedID: "c1", Size: 0, ETag: "", ShardKey: "sk1"},
			},
		},
		"coalesced_ec_with_nodes_parts": {
			Bucket: "bk", Key: "obj3", Size: 150, ETag: "etag3", ModTime: 1700000003,
			VersionID: "v3", PlacementGroupID: "g3",
			Coalesced: []CoalescedShardRef{
				{CoalescedID: "cc0", Size: 64, ETag: "cce0", ShardKey: "csk0", Version: 2,
					ECData: 4, ECParity: 2, StripeBytes: 4096, NodeIDs: []string{"n0", "n1", "n2"}},
			},
			Parts: []storage.MultipartPartEntry{
				{PartNumber: 1, Size: 100, ETag: "pe1"},
				{PartNumber: 2, Size: 0, ETag: "pe2"},
			},
			Tags: []storage.Tag{{Key: "a", Value: "1"}},
		},
	}
}

func byteIdentityObjectMetaFixtures() map[string]objectMeta {
	return map[string]objectMeta{
		"empty_vectors": {
			Key: "k", Size: 5, ETag: "e", PlacementGroupID: "g0",
		},
		"explicit_empty_slices": {
			Key: "k", Size: 5, ETag: "e", PlacementGroupID: "g0",
			Coalesced: []CoalescedShardRef{}, Parts: []storage.MultipartPartEntry{},
			Tags: []storage.Tag{},
		},
		"multi_tags": {
			Key: "obj", Size: 42, ETag: "etag", PlacementGroupID: "g1",
			Tags: []storage.Tag{{Key: "env", Value: "prod"}, {Key: "owner", Value: "alice"}},
		},
		"coalesced_zero_ec_no_nodes": {
			Key: "obj2", Size: 99, ETag: "etag2", PlacementGroupID: "g2",
			Coalesced: []CoalescedShardRef{
				{CoalescedID: "c0", Size: 10, ETag: "ce0", ShardKey: "sk0", Version: 1},
				{CoalescedID: "c1", Size: 0, ETag: "", ShardKey: "sk1"},
			},
		},
		"coalesced_ec_with_nodes_parts": {
			Key: "obj3", Size: 150, ETag: "etag3", PlacementGroupID: "g3",
			Coalesced: []CoalescedShardRef{
				{CoalescedID: "cc0", Size: 64, ETag: "cce0", ShardKey: "csk0", Version: 2,
					ECData: 4, ECParity: 2, StripeBytes: 4096, NodeIDs: []string{"n0", "n1", "n2"}},
			},
			Parts: []storage.MultipartPartEntry{
				{PartNumber: 1, Size: 100, ETag: "pe1"},
				{PartNumber: 2, Size: 0, ETag: "pe2"},
			},
			Tags: []storage.Tag{{Key: "a", Value: "1"}},
		},
	}
}

var goldenPutCmd = map[string]string{
	"empty_vectors":                 "28000000000000002000340030002c0020001c00180010000c00000000000000000000000400080020000000340000002c0000003400000000f153650000000030000000340000000500000000000000000000002c00000030000000000000000200000067300000020000007630000001000000650000000000000000000000010000006b00000002000000626b0000",
	"explicit_empty_slices":         "28000000000000002000340030002c0020001c00180010000c00000000000000000000000400080020000000340000002c0000003400000000f153650000000030000000340000000500000000000000000000002c00000030000000000000000200000067300000020000007630000001000000650000000000000000000000010000006b00000002000000626b0000",
	"multi_tags":                    "",
	"coalesced_zero_ec_no_nodes":    "",
	"coalesced_ec_with_nodes_parts": "",
}

var goldenObjectMeta = map[string]string{
	"empty_vectors":                 "240000000000000000001a0020001c00140010000c0000000000000000000000040008001a0000002000000018000000200000002400000005000000000000002000000000000000020000006730000001000000650000000000000000000000010000006b000000",
	"explicit_empty_slices":         "240000000000000000001a0020001c00140010000c0000000000000000000000040008001a0000002000000018000000200000002400000005000000000000002000000000000000020000006730000001000000650000000000000000000000010000006b000000",
	"multi_tags":                    "",
	"coalesced_zero_ec_no_nodes":    "",
	"coalesced_ec_with_nodes_parts": "",
}

// To refresh the golden maps above after an INTENTIONAL wire change, log the
// current marshal output from within one of the assertion tests below (e.g.
// t.Logf("%q: %s", name, hex.EncodeToString(buf))) and paste the values.

// TestByteIdentity_PutObjectMetaCmd asserts encodePutObjectMetaCmd output is
// byte-identical to the frozen golden captured from clean HEAD. Guards the
// coalesced/parts/tags vector-build dedup.
func TestByteIdentity_PutObjectMetaCmd(t *testing.T) {
	for name, c := range byteIdentityPutCmdFixtures() {
		want, ok := goldenPutCmd[name]
		require.True(t, ok, "missing golden for %q", name)
		buf, err := encodePutObjectMetaCmd(c)
		require.NoError(t, err)
		require.Equal(t, want, hex.EncodeToString(buf), "PutObjectMetaCmd %q wire bytes drifted", name)
	}
}

func TestByteIdentity_ObjectMeta(t *testing.T) {
	for name, m := range byteIdentityObjectMetaFixtures() {
		want, ok := goldenObjectMeta[name]
		require.True(t, ok, "missing golden for %q", name)
		buf, err := marshalObjectMeta(m)
		require.NoError(t, err)
		require.Equal(t, want, hex.EncodeToString(buf), "ObjectMeta %q wire bytes drifted", name)
	}
}
